 17	import useDuration from '@virtualmachines/details/tabs/metrics/hooks/useDuration';
 18	
 19	import ComponentReady from '../ComponentReady/ComponentReady';
 20	import useResponsiveCharts from '../hooks/useResponsiveCharts';
 21	import { getUtilizationQueries } from '../utils/queries';
 22	import {
 23	  findMaxYValue,
 24	  MILLISECONDS_MULTIPLIER,
 25	  queriesToLink,
 26	  tickFormat,
 27	  TICKS_COUNT,
 28	} from '../utils/utils';
 29	
 30	type StorageIOPSTotalThresholdChartProps = {
 31	  vmi: V1VirtualMachineInstance;
 32	};
 33	
 34	const StorageIOPSTotalThresholdChart: React.FC<StorageIOPSTotalThresholdChartProps> = ({ vmi }) => {
 35	  const { t } = useKubevirtTranslation();
 36	  const { currentTime, duration, timespan } = useDuration();
 37	  const queries = React.useMemo(
 38	    () => getUtilizationQueries({ duration, obj: vmi }),
 39	    [vmi, duration],
 40	  );
 41	  const { height, ref, width } = useResponsiveCharts();
 42	
 43	  const [data] = usePrometheusPoll({
 44	    endpoint: PrometheusEndpoint?.QUERY_RANGE,
 45	    endTime: currentTime,
 46	    namespace: vmi?.metadata?.namespace,
 47	    query: queries?.STORAGE_IOPS_TOTAL,
 48	    timespan,
 49	  });
 50	
 51	  const storageWriteData = data?.data?.result?.[0]?.values;
 52	
 53	  const chartData = storageWriteData?.map(([x, y]) => {
 54	    return { x: new Date(x * MILLISECONDS_MULTIPLIER), y: Number(y) };
 55	  });
 56	  const yMax = findMaxYValue(chartData);
 57	  const linkToMetrics = queriesToLink(queries.STORAGE_IOPS_TOTAL);
 58	
 59	  return (
 60	    <ComponentReady isReady={!isEmpty(chartData)} linkToMetrics={linkToMetrics}>
 61	      <div className="util-threshold-chart" ref={ref}>
 62	        <Link to={linkToMetrics}>
 63	          <Chart
 64	            containerComponent={
 65	              <ChartVoronoiContainer
 66	                constrainToVisibleArea
 67	                labels={({ datum }) => t('IOPS total: {{input}}', { input: datum?.y?.toFixed(2) })}
 68	              />
 69	            }
 70	            domain={{
 71	              x: [currentTime - timespan, currentTime],
 72	              y: [0, yMax],
 73	            }}
 74	            height={height}
 75	            padding={{ bottom: 35, left: 80, right: 35, top: 35 }}
 76	            scale={{ x: 'time', y: 'linear' }}
 77	            width={width}
 78	          >
 79	            <ChartAxis
 80	              style={{
 81	                grid: {
 82	                  stroke: chart_color_black_200.value,
 83	                },
 84	              }}
 85	              dependentAxis
 86	              tickFormat={(tick: number) => `${tick === 0 ? tick : tick?.toFixed(2)} IOPS`}
 87	              tickValues={[0, yMax]}
 88	            />
 89	            <ChartAxis
 90	              style={{
 91	                tickLabels: { padding: 2 },
 92	                ticks: { stroke: 'transparent' },
 93	              }}
 94	              axisComponent={<></>}
 95	              tickCount={TICKS_COUNT}
 96	              tickFormat={tickFormat(duration, currentTime)}
 97	            />
 98	            <ChartGroup>
 99	              <ChartArea
100	                style={{
101	                  data: {
102	                    stroke: chart_color_blue_300.value,
103	                  },
104	                }}
105	                data={chartData}
106	              />
107	            </ChartGroup>
108	          </Chart>
109	        </Link>
110	      </div>
111	    </ComponentReady>
112	  );
113	};
114	
115	export default StorageIOPSTotalThresholdChart;

